import{z}from"zod";import{v4 as uuidv4}from"uuid";import{checkWebSocketServerForUIProTool,getWebSocketServerForUIProTool}from"./utils.js";export const TOOL_SCHEMA_GET_NODES_TW_HTML=z.object({nodeIds:z.array(z.string()).optional()});export const TOOL_NAME_GET_NODES_TW_HTML="getHTMLTailwindCode";export const TOOL_DEFINITION_GET_NODES_TW_HTML={name:"getHTMLTailwindCode",description:'Generates HTML/Tailwind code of Figma nodes. If provided, uses the selected nodes in Figma. For images/assets, code can include pending_434:322, you can then use the id "434:322" to retrieve image using exportFigmaNode, If pending_nodeid is in the css then send isBG=true when exporting the image to get the image without children elements.',inputSchema:{type:"object",properties:{nodeIds:{type:"array",items:{type:"string"},description:"Optional array of Figma node IDs to generate code for. If not provided, uses the selected nodes."}},required:[]}};export async function runToolGetNodesTwHTML(args){try{const webSocketServer=getWebSocketServerForUIProTool(),serverCheckResult=checkWebSocketServerForUIProTool(webSocketServer);if(!serverCheckResult.valid)return serverCheckResult.data;const connectionManager=webSocketServer.getConnectionManager(),request={id:uuidv4(),type:"GET_NODES_TW_HTML",payload:args.nodeIds?{nodeIds:args.nodeIds}:void 0},response=await connectionManager.sendRequest(request,12e4);if(!response.success||response.error)return{isError:!0,content:[{type:"text",text:`Error generating code: ${response.error||"Unknown error"}`}]};if(!response.data||!response.data.html)return{isError:!0,content:[{type:"text",text:"No code generated. Make sure you have a node selected in Figma."}]};const{html:html,nodeIds:nodeIds}=response.data;return{content:[{type:"text",text:`Successfully generated Tailwind/HTML code for ${nodeIds.length} nodes: ${nodeIds.join(", ")}\n\n\`\`\`html\n${html}\n\`\`\``}]}}catch(error){return{isError:!0,content:[{type:"text",text:`Error generating code: ${error.message||error}`}]}}}